esqlQuery.esql:
FROM metrics-generic.otel-default
| WHERE metrics.zookeeper.request.active IS NOT NULL
// Average outstanding requests per node over the time window
| STATS avg_outstanding = AVG(metrics.zookeeper.request.active) BY host.name
// A healthy ensemble should have near-zero outstanding requests
// Sustained values above this threshold indicate processing saturation
// Adjust based on your workload; lower values catch issues sooner
| WHERE avg_outstanding > 10
